INSERT INTO dynamics (user_id, content, images, likes, views, comments, status, created_at) VALUES
(2, '今天早训放飞到80公里，归巢率95%，整体状态不错。有几羽状态特别好，下周准备加量到120公里。鸽友们有谁也在备战秋赛的吗？一起交流一下训放节奏。', NULL, 23, 342, 8, 1, '2026-06-09 08:30:00'),
(3, '公棚收鸽工作已过半，目前已入棚3200多羽。今年幼鸽整体质量比去年好，尤其詹森系和胡本系的后代状态不错。感谢各位鸽友的信任，我们会继续做好饲养管理工作。', NULL, 45, 567, 12, 1, '2026-06-08 14:20:00'),
(4, '分享一个血统搭配心得：最近用凡龙雄配詹森雌，出的幼鸽骨架非常硬朗，肌肉弹性也好。之前试过胡本配凡龙，速度上来了但耐力稍差。血统搭配真的是门大学问，有没有老铁分享一下自己的配方？', NULL, 67, 891, 23, 1, '2026-06-07 10:15:00'),
(5, '新手求教：刚入坑半年，养了十几羽，最近发现有两只鸽子老是打喷嚏，精神还行，吃喝也正常。需要用药吗？还是再观察？有经验的前辈帮忙看看。', NULL, 18, 445, 15, 1, '2026-06-07 16:40:00'),
(1, '【公告】近期有鸽友反映收到冒充公棚的诈骗电话，请大家提高警惕！正规公棚不会通过电话索要保证金或参赛费，所有收费都会通过官方渠道公示。如有疑问可直接联系公棚核实。', NULL, 89, 1203, 31, 1, '2026-06-06 09:00:00'),
(2, '昨晚鸽棚进了一只猫，吓死了！还好发现及时，只丢了一羽幼鸽。连夜加固了鸽棚防护网，鸽友们一定要注意防范啊，尤其是这个季节野猫活动频繁。养鸽子真是操不完的心 😤', NULL, 56, 723, 19, 1, '2026-06-06 22:30:00'),
(4, '今年的杨欧瓦克血系表现非常惊艳，300公里热身赛前十进了三羽！这个血统的抗逆性和定向能力确实名不虚传。有计划引入这个血统的鸽友可以关注一下，个人强烈推荐。', NULL, 72, 945, 26, 1, '2026-06-05 11:50:00'),
(3, '公棚饲料调整记录：进入雨季湿度大，适当增加了高粱和豌豆的比例，减少了玉米用量。同时饲料中添加了啤酒酵母和蒜油，增强鸽子免疫力。目前观察粪便成型度良好，飞行状态稳定。持续跟踪中。', NULL, 34, 489, 9, 1, '2026-06-05 08:10:00'),
(5, '上周末去鸽市淘了一羽佛卡门原环子代，手感、眼砂、骨架都非常满意！花了一个月工资，但值了！等适应期过了配上家里的詹森，看看能不能出几羽好苗子。玩鸽子就是这样，永远在期待下一羽 😄', NULL, 41, 678, 16, 1, '2026-06-04 15:20:00'),
(2, '秋赛倒计时两个月，整理一下目前的种鸽阵容：主力还是勃默德配詹森邦德007那路，稳定性没得说。去年500公里决赛归巢6羽，今年目标进前十！鸽友们一起加油 💪', NULL, 38, 564, 11, 1, '2026-06-03 20:00:00');
